INSERT INTO `mobile_faq` (`FAQ_id`, `mobile_id`, `FAQ_Question`, `FAQ_Answer`, `created_at`) VALUES
(1, 40, 'What is the display size of OPPO Reno 14F 5G?', 'It features a 6.57-inch AMOLED display with FHD+ resolution and a 120Hz refresh rate for smooth visuals.', '2025-11-28 06:03:50'),
(2, 40, 'Which processor does Reno 14F 5G use?', 'The phone is powered by the Qualcomm Snapdragon 6 Gen 1 chipset with Adreno 710 GPU, suitable for daily tasks and light to medium gaming.', '2025-11-28 06:04:33'),
(3, 40, 'What are the camera specifications?', 'It has a triple rear camera setup: 50MP main (OIS), 8MP ultrawide, and 2MP macro. The front camera is 32MP, ideal for selfies and video calls.', '2025-11-28 06:04:57'),
(4, 40, 'How big is the battery and does it support fast charging?', 'It comes with a 6000mAh battery and 45W SUPERVOOC fast charging, providing long-lasting usage and quick recharge.', '2025-11-28 06:05:23'),
(5, 42, 'How good is the screen?', 'Super smooth 6.67-inch AMOLED display with 120Hz refresh rate.', '2025-11-30 07:12:23'),
(6, 42, 'What about the cameras?', '50MP main + 8MP ultra-wide rear cameras and 50MP front camera for selfies and videos', '2025-11-30 07:12:41'),
(7, 42, 'How long does the battery last?', '5000mAh battery with 66W fast chargingâ€”enough for a full day of use.', '2025-11-30 07:12:56');
INSERT INTO `mobile_highlights` (`highlight_id`, `mobile_id`, `highlight_text`, `created_at`) VALUES
(1, 1, '[\"Vivo Y16\",\"Funtouch OS 12\",\"Android 12\",\"MediaTek Helio G35\",\"Octa-core processor\",\"6.51-inch HD+ display\",\"5000mAh battery\",\"13MP + 2MP dual rear camera\",\"5MP front camera\",\"HDR camera\",\"32GB\\/64GB storage\",\"3GB\\/4GB RAM\",\"LPDDR4X RAM\",\"MicroSD expandable\",\"eMMC 5.1\",\"Budget smartphone\",\"User-friendly UI\",\"Lightweight phone\"]', '2025-10-04 18:47:25'),
(4, 3, '[\"Xiaomi Mix Flip\",\"Release Date:19-Jul-2024\",\"Variant: RAM: 12GB + ROM: 256GB\",\"Foldable smartphone with sleek aluminum and glass body weighing 234\",\"Main 6.86-inch LTPO OLED display with 120Hz adaptive refresh rate and HDR10+ support\",\"Secondary 1.9-inch cover display for quick notifications\",\"High-resolution 1840 x 2480 pixels (400 ppi) with up to 1000 nits brightness\",\"Under-display selfie camera\",\"no visible notch\",\"Available in Phantom Black and Phantom Purple\",\"\"]', '2025-10-05 14:22:58'),
(6, 5, '[\"Price in Bangladesh: BDT 230\",\"000 (approx.)\",\"Processor: Snapdragon 8 Gen 2\",\"Display: AMOLED Dual Flagship Screen\",\"Camera: Leica Quad Camera Setup\",\"Battery: 4800mAh with 67W Fast Charging\",\"Storage: UFS 4.0 High-Speed Storage\",\"Cooling: VC Heat Dissipation System\",\"Build: Ultra-Slim\",\"Durable Hinge Design\",\"Built with super steel hinge the Xiaomi Mix Fold 3 is flexible yet durable ensuring long-lasting foldable performance\",\"High-quality videos with the full-focus quad-camera setup featuring Leica optical lenses\",\"The foldable phone a premium and stylish look\",\"Xiaomi brightest flagship displays delivering vivid and clear visuals\",\"Snapdragon 8 Gen 2 processor and UFC 4.0 ultra-fast storage the device ensures smooth multitasking and high-speed performance\",\"The VC cooling system efficiently dissipates heat reducing lag during heavy gaming or extended usage\",\"Optimized battery with fast charging keeps you powered for longer and allows quick recharges\",\"\"]', '2025-10-05 15:58:06'),
(7, 6, '[\"5.0-inch Super AMOLED HD Display â€“ Bright colorful and battery-efficient screen for a better viewing experience.\",\"Qualcomm Snapdragon 410 Processor â€“ Smooth multitasking with Quad-core 1.2 GHz Cortex-A53 CPU.\",\"13 MP Rear Camera (f\\/1.9) with LED Flash â€“ Clear\",\"vibrant photos and Full HD video recording.\",\"5 MP Front Camera with LED Flash â€“ Perfect for selfies even in low-light conditions.\",\"2600 mAh Removable Battery â€“ Full-day battery life with easy replacement option.\",\"Expandable Storage up to 128GB â€“ Extra space for apps photos and videos.\",\"Slim & Lightweight Design (7.9 mm 146g) â€“ Comfortable grip and elegant finish.\",\"Affordable Price (BDT 13\",\"990 in Bangladesh) â€“ Excellent value for money in the budget range.\",\"Upgradable Android (Lollipop â†’ Marshmallow) â€“ Improved features and performance with software upgrade.\",\"Connectivity Options: Wi-Fi Bluetooth 4.1 GPS FM Radio & NFC (market-dependent).\",\"\"]', '2025-10-05 17:10:01'),
(8, 7, '[\"7000â€¯mAh Battery â€“ Typical 7000â€¯mAh supports 80W SUPERVOOC fast charging and reverse wired charging for other devices.\",\"5G Connectivity â€“ Supports next-gen 5G network for faster downloads gaming and streaming.\",\"Large 6.57-inch Display â€“ 120Hz refresh rate 93% screen-to-body ratio bright AMOLED panel perfect for media and gaming.\",\"Vapor Chamber Cooling (VC) â€“ Advanced cooling system keeps the device 1.5Â°C cooler during gaming improves performance and stability.\",\"Durable & Waterproof Design â€“ IP66\\/IP68\\/IP69 certified; MIL-STD 810H drop-tested for high-intensity impact protection.\",\"AI Features â€“ OPPO AI features for camera system optimization and game\\/network enhancements (may vary by region & OTA updates).\",\"Large RAM & Storage Options â€“ 8GB RAM with virtual RAM expansion storage variants of 128GB & 256GB.\",\"Camera Excellence â€“ High-quality rear and front cameras with Motion Photo AI enhancements and professional-level photography options.\",\"Touchscreen Gloves Support â€“ Can operate touchscreen with gloves up to 5mm thick (cotton wool sheepskin).\",\"Long-Term Fluency Protection â€“ Software & hardware optimizations ensure smooth performance up to 60 months keeping device responsive over time.\",\"\"]', '2025-10-07 11:33:29'),
(9, 8, '[\"Available in 8GB RAM + 128GB and 12GB RAM + 256GB storage options with microSDXC support.\",\"Powerful Processor â€“MediaTek Dimensity 7300 Ultimate (4nm) Octa-core CPU (4x 2.5 GHz Cortex-A78 & 4x 2.0 GHz Cortex-A55) for smooth multitasking and gaming.\",\"Operating System â€“Android 15 and HiOS 15 for enhanced performance and features.\",\"Display â€“6.78-inch AMOLED display with 1224 x 2720 pixels resolution 144Hz refresh rate and Corning Gorilla Glass 3 protection.\",\"Dual Rear Camera â€“ 64MP primary + 8MP secondary camera for crisp and clear photos.\",\"Front Camera â€“ 13MP selfie camera for perfect selfies and video.\",\"Battery & Fast Charging â€“ 6000mAh battery with 45W fast charging ensures long-lasting usage.\",\"Network Support â€“ Fully supports 2G 3G 4G and 5G networks with dual nano SIM slots.\",\"Biometric Security â€“ Under-display fingerprint sensor for fast and secure access.\",\"Extra Features â€“ Includes WLAN Bluetooth USB ports Delta Light Interface RAM Expansion and PinPoint Nav 2.0 for enhanced usability.\",\"\"]', '2025-10-07 18:14:26'),
(10, 9, '[\"Tecno Spark 40 is a 6.67-inch IPS LCD display with 120Hz refresh rate for smooth visuals.\",\"50MP AI dual rear camera ensures high-resolution photography and low-light clarity.\",\"8MP front camera with dual LED flash for bright and clear selfies.\",\"5200mAh battery with 45W fast charging keeps your phone active all day.\",\"Android 15 with HiOS 15.1 offers a seamless and AI-powered user experience.\",\"MediaTek Helio G81 Octa-core chipset delivers smooth performance for gaming and multitasking.\",\"Dual SIM support with microSD expansion allows flexible storage and connectivity options.\",\"Side-mounted fingerprint sensor and face unlock ensure quick and secure access.\",\"IP64 splash and dust resistant design protects your device in daily use.\",\"Stereo speakers 3.5mm audio jack and infrared remote enhance entertainment and usability.\",\"\"]', '2025-10-08 07:00:55'),
(11, 10, '[\"Tecno Pova Slim 5G\",\"AMOLED 144Hz Display\",\"50MP Camera\",\"5160mAh Battery\",\"Ella AI Assistant\",\"MIL-STD 810H Durable\",\"Dolby Atmos Speakers\",\"Thin & Light Design\",\"128GB\\/256GB Storage\",\"Android 15 HiOS 15\"]', '2025-10-08 10:41:38'),
(12, 11, '[\"6.78\\\" AMOLED display 144Hz refresh rate\",\"MediaTek Dimensity 7300 Ultra processor\",\"8GB RAM + 128GB storage\",\"64MP + 2MP dual rear camera\",\"13MP front camera\",\"4K video recording support\",\"5500mAh battery 45W fast charging\",\"In-display fingerprint + face unlock\",\"5G Wi-Fi 6  Bluetooth 5.4 NFC\",\"Stereo speakers with Dolby Atmos\",\"\"]', '2025-10-08 15:53:11'),
(13, 12, '[\"Display: 6.9-inch Super Retina XDR OLED with 120Hz ProMotion for smooth visuals\",\"Processor: Apple A19 Pro chip for fast performance and gaming\",\"RAM & Storage: 12GB RAM with 256GB \\/ 512GB \\/ 1TB \\/ 2TB storage options\",\"Camera: Triple 48MP rear + 18MP front camera\",\"8K video recording\",\"cinematic photography\",\"Face ID: Advanced facial recognition for secure authentication\",\"Operating System: iOS 26 with smooth UI and latest Apple features\",\"Connectivity: 5G Wi-Fi 7 Bluetooth 6 USB-C MagSafe for fast and reliable connections\",\"Battery: 4832mAh with fast charging and long-lasting performance\",\"Design: Premium titanium finish IP68 water & dust resistant\",\"Price in Bangladesh: Starting from BDT 200 000 best flagship option in 2025\"]', '2025-10-09 06:09:36'),
(14, 13, '[\"6.9-inch IPS LCD HD+ resolution adaptive brightness support\",\"Snapdragon 6s Gen 3 5G 6nm process 64-bit octa-core 2Ã—A78 6Ã—A55\",\"6GB or 8GB LPDDR4X RAM 128GB or 256GB UFS 2.2 storage microSD expandable\",\"50MP main camera 8MP front camera night mode AI photography\",\"5000mAh battery fast charging supported long-lasting usage\",\"5G connectivity 4G LTE compatible\",\"Slim plastic body lightweight ~200g matte or metallic finish durable design\",\"Android 13 MIUI 15 upgradable smooth UI system updates supported\",\"Adreno GPU smooth gameplay high FPS support casual and competitive gaming friendly\",\"Fingerprint sensor face unlock MIUI security features\",\"RAM and Storage options 6GB 128GB 8GB 128GB 8GB 256GB Colors Gray Sandy Blue Red\"]', '2025-10-11 15:06:27'),
(15, 14, '[\"Display\",\"6.9-inch LTPO AMOLED_1200 Ã— 2608 pixels\",\"120Hz refresh rate with HDR10+ support\",\"Processor\",\"Qualcomm Snapdragon 8 Elite Gen 5 (3nm)\",\"High-performance CPU and GPU for gaming and multitasking\",\"RAM & Storage\",\"12GB \\/ 16GB RAM\",\"512GB \\/ 1TB UFS 4.0 storage\",\"Camera\",\"Rear: Triple 50MP (wide telephoto ultrawide)\",\"Front: 50MP high-resolution selfie camera\",\"Video: 8K recording support\",\"Battery & Charging\",\"7500mAh battery\",\"100W fast charging support\",\"Long-lasting battery life\",\"Android 16 with HyperOS 3\",\"Dual rear display\",\"IP68 water and dust resistance\",\"Wi-Fi 7_Bluetooth 5.4_5G connectivity\",\"\"]', '2025-10-12 16:47:17'),
(16, 15, '[\"6.3-inch Super Retina XDR OLED Display (120Hz Refresh)\",\"iOS 26 with new Liquid Glass UI\",\"Apple A19 Bionic Chip (3nm architecture)\",\"8\\/12GB RAM with 256GB \\/ 512GB \\/ 1TB Storage\",\"Dual Rear Camera (48MP Main + 12MP Ultra-Wide)\",\"12MP Front Camera with Face ID\",\"Aerospace-grade Aluminum Body\",\"No Fingerprint Sensor (Face ID only)\",\"5G + Wi-Fi 7 + Bluetooth 5.4\",\"30W Fast Charging & 15W MagSafe Wireless Charging\",\"3900 mAh Battery (approx.)\",\"IP68 Dust & Water Resistant\",\"Dynamic Island (Enhanced Version)\",\"Available Colors: Space Black-Cloud White-Light Gold-Sky Blue\"]', '2025-10-12 19:50:20'),
(17, 17, '[\"Battery & Charging: Vivo Y21d is 6500mAh battery with 44W FlashCharge.\",\"Build & Durability: IP68 and IP69+ certification making it dustproof and water-resistant able to survive accidental splashes and even short immersion in water.\",\"Camera: Vivo Y21d dual rear camera setup with a 50MP primary sensor delivering high-quality photos and sharp details in every shot.\",\"Display: The 6.68-inch screen 90Hz refresh rate providing smooth visuals for gaming-videos.\",\"Expandable Storage: With 128GB internal storage and support for microSD up to 2TB.\",\"\"]', '2025-10-13 17:24:53'),
(18, 18, '[\"Chipset: MediaTek Dimensity 6300 5G\",\"RAM: 4GB \\/ 6GB LPDDR4X\",\"Dynamic RAM up to 18GB\",\"Storage: 128GB UFS 2.2 expandable up to 2TB via microSD\",\"Display: 6.67-inch HD+ (1604 x 720 pixels) IPS LCD 120Hz refresh rate\",\"Battery: 6000mAh-45W fast charging\",\"Camera:\",\"Rear: 32MP primary camera\",\"Front: 8MP selfie camera\",\"Design: Lily-inspired design-IP64 rating-military-grade shock resistance\",\"Operating System: Android 15-Realme UI 6.0\",\"Connectivity: 5G-Dual SIM-Wi-Fi-Bluetooth 5.3\",\"Extra Features: Side-mounted fingerprint sensor-Face Unlock-180Â° Super Linear Speaker\",\"\"]', '2025-10-13 19:31:28'),
(19, 16, '[\"Processor: Snapdragon 4 Gen 2 (4 nm) power-efficient chipset for smooth performance.\",\"Battery & Charging: 6500 mAh battery with 44W fast charging support.\",\"Display: 6.68-inch IPS LCD panel with 120Hz refresh rate and 84% screen-to-body ratio.\",\"Camera: 50MP main rear camera + auxiliary lens and 8MP front camera with 1080p@30fps video recording.\",\"Durability: IP68 \\/ IP69 water and dust resistance for strong build quality.\",\"Software & Storage: Android 15 with Funtouch OS 15 128GB storage and 4GB or 6GB RAM.\",\"Price & Value: Expected Bangladesh price â‰ˆ 22000BDT â€“ 27000BDT.\",\"\"]', '2025-10-14 15:32:00'),
(20, 19, '[\"Display: 6.7-inch FHD+ Super AMOLED-90Hz refresh rate-protected by Corning Gorilla Glass Victus.\",\"Processor: Exynos 1330 chipset with an octa-core CPU (2x2.4 GHz Cortex-A78 & 6x2.0 GHz Cortex-A55) and Mali-G68 MP2 GPU.\",\"Camera: Triple rear camerasâ€”50MP (wide)-5MP (ultra-wide)-and 2MP (macro)-13MP front camera.\",\"Battery: 5000mAh capacity with 25W fast charging support.\",\"Operating System: Android v15 with One UI 7.\",\"Build & Design: Glass front (Gorilla Glass Victus) plastic frame-glass fiber back-IP54 splashproof rating.\",\"Connectivity: Supports 5G-Wi-Fi 5-Bluetooth 5.3-NFC and USB Type-C 2.0.\",\"Storage & RAM: 6GB RAM (LPDDR4X) and 128GB internal storage (UFS 2.2)-expandable up to 2TB.\",\"\"]', '2025-10-14 16:23:33'),
(21, 21, '[\"6000 mAh large battery with fast charging support\",\"50 MP primary camera + 8 MP selfie camera\",\"6.6-inch Full HD+ display-120Hz refresh rate-HDR support\",\"MediaTek Dimensity 6300 chipset-Octa-core CPU-Mali-G57 GPU\",\"8 GB RAM + 128\\/256 GB internal storage- microSDXC support\",\"Android 15 with ColorOS 15 UI\",\"Dual SIM-5G network-VoLTE-NFC support\",\"Side-mounted fingerprint sensor + Face Unlock\",\"USB Type-C port-3.5 mm audio jack-stereo speakers\",\"Slim and lightweight design-available in White & Black\"]', '2025-10-14 17:38:18'),
(22, 22, '[\"Lagship 5G Smartphone with Android 15 support\",\"High Resolution 200MP primary camera with Ultra Wide and Telephoto lenses\",\"Powerful performance with latest Snapdragon processor and 12GB RAM with up to 1TB storage\",\"Stunning Super AMOLED display with 120Hz refresh rate and HDR10+ support\",\"Fast 45W charging and Wireless Charging support\",\"Long lasting 5000mAh battery for all day usage\",\"Premium titanium body design with S Pen support\",\"Official launch and price available in Bangladesh at Mobiledokan Pickaboo and Daraz\",\"AI Camera features with 8K video recording and Ultra Wide lens\",\"Waterproof design with USB Type-C and wireless charging compatibility\"]', '2025-10-16 18:50:27'),
(24, 23, '[\"Powerful Snapdragon 8 Elite (3 nm) Processor â€“ Ensures ultra-fast performance and smooth multitasking.\",\"12GB RAM with up to 256GB Storage â€“ Ideal for gaming-photography and daily use.\",\"6.2-inch LTPO AMOLED 2X Display (120Hz) â€“ Offers vibrant colors sharp visuals and a 2600 nits peak brightness.\",\"Premium Design with Gorilla Glass Victus 2 â€“ Built to last with a sleek aluminum frame.\",\"Triple Rear Camera Setup (50MP + 10MP + 12MP) â€“ Capture stunning photos and 8K videos with OIS support.\",\"12MP Front Camera â€“ Delivers clear and natural selfies even in low light.\",\"4000mAh Battery with 25W Fast Charging â€“ Get 50% charge in just 30 minutes also supports 15W wireless charging.\",\"5G Wi-Fi 7  and Bluetooth 5.4 â€“ Ensures next-level connectivity and faster data speeds.\",\"IP68 Water and Dust Resistance â€“ Reliable in any weather\",\"protecting your phone from splashes and dust.\",\"Ultrasonic In-Display Fingerprint Sensor â€“ Fast secure and convenient unlocking experience.\"]', '2025-10-17 19:10:30'),
(25, 24, '[\"Display: 6.73-inch Quad-Curved AMOLED 2K resolution-120Hz refresh rate\",\"Protection: Corning Gorilla Glass for superior durability\",\"Processor: Qualcomm SM8750-AB Snapdragon 8 Elite\",\"Operating System: Android 15 with Xiaomi HyperOS 2\",\"Rear Camera Setup:\",\"50MP Main Camera with OIS\",\"50MP Telephoto Lens (3.2x Optical Zoom)\",\"200MP Periscope Telephoto Camera\",\"50MP Ultra-Wide Camera\",\"Front Camera: 32MP for high-quality selfies\",\"IP Rating: IP68 Dust and Water Resistant\",\"Charging: 90W Fast Wired Charging & 80W Wireless Charging\",\"Storage & RAM: 16GB RAM + 512GB Internal Storage\",\"Price in Bangladesh: BDT 160000 (Unofficial)\"]', '2025-10-18 18:54:28'),
(26, 25, '[\"Flagship Performance: Powered by the latest Qualcomm Snapdragon 8 Elite processor for ultra-fast speed and smooth gaming.\",\"Vibrant Display: Large 6.82-inch LTPO AMOLED QHD+ screen with 120Hz refresh rate for crystal-clear visuals.\",\"High RAM & Storage: Comes in 12GB+256GB and 16GB+512GB variants for heavy multitasking and storage needs.\",\"Triple 50MP Camera Setup: Includes 50MP Sony main-50MP telephoto (3x zoom)- and 50MP ultra-wide lenses.\",\"Powerful Selfie Camera: 32MP front camera for high-quality selfies and video calls.\",\"Massive Battery: 6000mAh battery ensures all-day performance without frequent charging.\",\"Super-Fast Charging: 100W wired and 50W wireless charging support for quick power-ups.\",\"Premium Build & Design: Sleek modern look with flagship-level durability and aesthetics.\",\"Latest Software: Runs on Android 15 with OxygenOS offering smooth and clean user experience.\",\"Unofficial Price in Bangladesh: BDT 129500 for the 16GB+512GB model (as of 2025).\",\"\"]', '2025-10-21 14:53:18'),
(27, 26, '[\"Google Pixel 10 Pro Launch in Bangladesh: Event on August 20\",\"2025\",\"in New York City.\",\"Part of Pixel 10 Series: Includes Pixel 10 -Pixel 10 Pro- Pixel 10 Pro XL-and Pixel 10 Pro Plus.\\r\\nMaterial 3 Expressive UI: Offers a customizable and smooth user interface for better user experience.\",\"Google Tensor G5 Chip: Ensures AI-powered performance and fast processing.\",\"Triple Rear Camera System: High-quality photography and advanced camera features.\",\"Large AMOLED Display: High-resolution screen with smooth refresh rate for immersive visuals.\",\"AI Tools & Smart Features: Includes Magic Cue Daily Hub and Ask Photos for smart user assistance.\",\"Customizable Quick Settings & Gestures: Easier navigation and personalized control.\",\"Premium Design & Build Quality: Sleek design with durable materials for a modern look.\",\"Optimized Battery & Fast Charging: Long-lasting battery life with fast charging support.\"]', '2025-10-21 16:16:03'),
(28, 27, '[\"Large 6.7 inch super amoled display with 90hz refresh rate\",\"50mp main camera with ois performs well in day and night\",\"13mp selfie camera perfect for social media\",\"exynos 1330 chipset suitable for daily use and light gaming\",\"5000mah battery with 25w fast charging support\",\"android 15 and one ui 7 provide user friendly software experience\",\"ram and storage variants 6gb and 8gb ram with 128gb and 512gb storage\",\"budget friendly price easily available in Bangladesh\",\"sufficient performance for casual gaming and media consumption\",\"long term software update support\"]', '2025-10-21 18:28:05'),
(29, 28, '[\"Vivo X300 Pro is powered by MediaTek Dimensity 9500 3nm chipset for flagship-level performance\",\"It offers smooth gaming experience with high refresh rate and strong GPU performance\",\"Triple rear camera setup includes a 200MP periscope zoom lens with OIS support\",\"Comes with a massive 6510mAh battery featuring 90W fast charging and 40W wireless charging\",\"Features a 6.78-inch AMOLED display with 120Hz refresh rate for vivid and fluid visuals\",\"Provides up to 16GB RAM and 1TB storage for seamless multitasking and storage capacity\",\"Vivo X300 Pro price in Bangladesh makes it a powerful competitor in 2025\"]', '2025-10-21 19:20:59'),
(30, 29, '[\"200MP Main Camera â€“ Ultra-high resolution photos.\",\"50MP Front Camera â€“ Perfect for sharp selfies and video calls.\",\"6.77-inch AMOLED Display â€“ Vibrant colors with deep contrasts.\",\"20:9 Aspect Ratio â€“ Tall-immersive screen ideal for videos and browsing.\",\"Full HD+ Resolution (1080 x 2392 pixels) â€“ Clear and detailed visuals.\",\"120Hz Refresh Rate â€“ Smooth scrolling-gaming-and video playback.\",\"MediaTek Dimensity 7360 Turbo Chipset â€“ Powerful performance for multitasking and gaming.\",\"6500mAh Battery â€“ Long-lasting power for all-day usage.\",\"90W Fast Charging â€“ Quickly charges the phone in minutes.\",\"Elegant Color Options â€“ Elite Purple and Noble Gold for a premium look.\"]', '2025-10-23 17:29:11'),
(31, 30, '[\"6.67-inch AMOLED Display â€“ 120Hz refresh rate crystal-clear visual experience.\",\"Snapdragon 7 Gen 4 Processor â€“ blazing-fast performance for gaming and multitasking.\",\"50MP Sony Camera Setup â€“ clarity with ultra-wide support.\",\"32MP Front Camera â€“ perfect selfies and smooth video calls.\",\"8GB\\/12GB RAM + 128GB\\/256GB Storage â€“ smooth multitasking and ample space.\",\"6500mAh Battery with 90W Flash Charging with revers charging.\",\"5G Connectivity â€“ future-ready network speed.\",\"Curved AMOLED Design â€“ premium look with ultra-slim body.\",\"In-display Fingerprint Sensor.\",\"Water & Dust Resistance (IP68 Rated) â€“ built to endure any environment.\"]', '2025-10-23 18:22:58'),
(32, 31, '[\"Display: 5.7-inch IPS LCD with 18:9 aspect ratio.\",\"Processor: Qualcomm Snapdragon 450 Octa-core.\",\"RAM & Storage: 3GB\\/4GB RAM with 32GB\\/64GB storage.\",\"Camera: Dual rear camera 12MP + 5MP-front camera 8MP.\",\"Battery: 3000 mAh with fast charging support.\",\"Operating System: Android 8.0 Oreo.\",\"Design: Glass front and back with metal frame.\",\"Connectivity: 4G LTE-Wi-Fi-Bluetooth 4.2-no NFC.\",\"Fingerprint Sensor: Rear-mounted fingerprint scanner.\",\"Audio: 3.5mm headphone jack with Dolby Audio support.\"]', '2025-10-23 19:24:43'),
(33, 32, '[\"Display & Build: 6.6-inch Dynamic AMOLED 2X display with 120Hz refresh rate â€“ delivers a smooth experience for gaming\",\"videos and scrolling.\\r\\nCamera Setup: Triple camera â€“ 50MP main\",\"10MP 3Ã— telephoto 12MP ultrawide. Video recording supports 8K and 4K @30\\/60fps.\\r\\nPerformance: Exynos 2200 or Snapdragon 8 Gen 1 chipset 8GB RAM and 128\\/256GB storage â€“ perfect for multitasking and heavy gaming.\\r\\nCharging & Battery: 4500mAh battery with 45W wired 15W wireless and reverse wireless charging.\\r\\nConnectivity: 5G support Wi-Fi 6 and Bluetooth 5.2 â€“ ensures fast and reliable connectivity.\"]', '2025-10-30 15:48:20'),
(34, 33, '[\"6.9-inch 2K OLED display with 2608x1200 resolution 120Hz refresh rate 12-bit color and 3500 nits brightness\",\"Snapdragon 8 Elite Gen 5 chipset built on 3nm process for flagship performance\",\"Up to 12GB LPDDR5x RAM and 1TB UFS 4.1 storage\",\"50MP main sensor with OIS\",\"50MP periscope telephoto lens with 5x optical zoom\",\"50MP ultra-wide camera\",\"7560mAh silicon-carbon battery with 100W wired charging 50W wireless charging and 22.5W reverse charging\",\"Dual speaker system tuned by Bose with 2.1 channel setup and rear subwoofer\",\"IP68 dust and water resistance with in-display ultrasonic fingerprint sensor\",\"HyperOS 3 based on Android 16\"]', '2025-11-01 17:57:17'),
(35, 34, '[\"144Hz LTPO AMOLED Display\",\"Snapdragon 8 Elite Processor\",\"5000â€“7500mAh Battery\",\"50MP OIS Rear Camera\",\"20:9 Aspect Ratio\",\"5G Connectivity\",\"Up to 16GB RAM\",\"High Brightness (â‰ˆ4500 nits)\",\"Premium Design\",\"Gaming-Focused Features\"]', '2025-11-04 17:35:40'),
(36, 35, '[\"6.8-inch FHD+ AMOLED Display â€” 120Hz\",\"Snapdragon 685 Processor (6 nm)\",\"8GB LPDDR4x RAM + up to 24GB Dynamic Expansion\",\"UFS 2.2 Storage (128GB \\/ 256GB)\",\"Massive 7000 mAh Battery\",\"50MP AI Dual Camera Setup\",\"8MP Front Camera\",\"IP69 Pro Water & Dust Resistant\",\"144Hz Touch Sampling Rate\",\"Affordable Flagship Killer\",\"\"]', '2025-11-05 12:23:46'),
(37, 39, '[\"Massive 7000mAh battery for 2â€“3 days of heavy use.\",\"30W fast charging for quicker top-ups.\",\"6.7-inch FHD+ 120Hz display for smooth scrolling and media.\",\"Snapdragon mid-range chipset suitable for daily tasks and light gaming.\",\"50MP main camera + ultrawide + 32MP selfie for decent photography.\",\"4K video recording on both front and rear cameras.\",\"Dual stereo speakers + 3.5mm headphone jack with rich audio output.\",\"P64 water & dust resistance with durable build quality.\",\"Android 15 with expected future updates.\",\"Great value for money in the mid-range segment.\"]', '2025-11-27 15:35:14'),
(38, 40, '[\"50MP OIS main camera delivers crisp photos and steady videos.\",\"Snapdragon 6 Gen 1 ensures smooth everyday performance.\",\"6.57 inch AMOLED 120Hz display for vibrant and fluid visuals.\",\"6000mAh large battery for all-day power backup.\",\"Slim-ightweight design with glass front and plastic frame.\"]', '2025-11-28 05:51:57'),
(40, 41, '[\"Chipset: Qualcomm SM8850-AC Snapdragon 8 Elite Gen 5\",\"RAM: 12 GB LPDDR5X\",\"Dynamic RAM up to 18GB\",\"Storage: 256GB\\/512GB UFS 4.1.\\r\\nDisplay: 6.79-inch HD+ (1440 x 3136 pixels)  LTPO AMOLED 144Hz refresh rate\",\"Battery: 7000mAh-1200W fast charging\",\"Camera:\",\"Rear: 50MP primary camera\",\"Front: 32MP selfie camera\",\"Design: Glass front\",\"aluminum frame\",\"fiberglass back or silicone polymer (eco leather) back  design-IP68 \\/IP69 rating-military-grade shock resistance\",\"Color: Blue\",\"Green\",\"White\\r\\nOperating System: Android 16-Realme UI 17.0\",\"Connectivity: 5G-Dual SIM-Wi-Fi-Bluetooth 6.0\",\"Extra Features: On-screen fingerprint  sensor-Face.\"]', '2025-11-28 06:48:17'),
(41, 42, '[\"6.67-inch 1.5K AMOLED Display with 120Hz refresh rate\",\"2400 nits brightness for super clear\",\"MediaTek Dimensity 8350 (4nm) powerful chipset\",\"8GB LPDDR5X RAM + 256GB UFS 4.0 storage\",\"50MP OIS main camera + 8MP ultrawide\",\"50MP 4K selfie camera\",\"5000mAh battery with 66W fast charging\",\"Android 15 (no bloatware)\",\"3 years OS updates\",\"WiFi 6E-Bluetooth 5.4-Type-C 3.2\",\"In-display fingerprint\",\"Premium glass-metal design\"]', '2025-11-30 07:10:04'),
(42, 43, '[\"MediaTek Dimensity 9500 Flagship Chipset\",\"120Hz AMOLED Premium Display\",\"Triple 50MP Pro Camera System\",\"Massive 7025mAh Battery\",\"Super Premium Build (Glass + Aluminum)\",\"Fast Charging\",\"Advanced AI Photography & Video\",\"Future-Proof 5G Connectivity\"]', '2025-12-05 19:54:09');
